331	2026-05-19 01:00:22.137184+00	2026-05-19 01:00:22.137184+00	["{\\"description\\":\\"Distribución de pedidos e ingresos entre canal físico y digital para decisiones de estrategia comercial.\\",\\"archived\\":false,\\"collection_position\\":null,\\"table_id\\":null,\\"database_id\\":2,\\"enable_embedding\\":false,\\"collection_id\\":null,\\"query_type\\":\\"native\\",\\"name\\":\\"Ventas por canal: tienda vs online\\",\\"type\\":\\"question\\",\\"embedding_params\\":null,\\"cache_ttl\\":null,\\"dataset_query\\":{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    pe.canal,\\\\r\\\\n    COUNT(pe.id_pedido) AS total_pedidos,\\\\r\\\\n    SUM(p.monto) AS ingresos_totales\\\\r\\\\nFROM pedido pe\\\\r\\\\nJOIN pago p ON pe.id_pedido = p.id_pedido\\\\r\\\\nWHERE pe.estado = 'completado'\\\\r\\\\nGROUP BY pe.canal;\\"}},\\"parameter_mappings\\":[],\\"display\\":\\"pie\\",\\"collection_preview\\":true,\\"visualization_settings\\":{\\"pie.dimension\\":\\"canal\\",\\"pie.metric\\":\\"ingresos_totales\\"},\\"parameters\\":[]}","{\\"description\\":\\"Distribución de pedidos por estado (completado, cancelado, devuelto, pendiente) para identificar el nivel de riesgo operacional del negocio.\\",\\"archived\\":false,\\"collection_position\\":null,\\"table_id\\":null,\\"database_id\\":2,\\"enable_embedding\\":false,\\"collection_id\\":null,\\"query_type\\":\\"native\\",\\"name\\":\\"Tasa de pedidos cancelados y devueltos\\",\\"type\\":\\"question\\",\\"embedding_params\\":null,\\"cache_ttl\\":null,\\"dataset_query\\":{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    estado,\\\\r\\\\n    COUNT(*) AS total,\\\\r\\\\n    ROUND(COUNT(*) * 100.0 / SUM(COUNT(*)) OVER (), 2) AS porcentaje\\\\r\\\\nFROM pedido\\\\r\\\\nGROUP BY estado\\\\r\\\\nORDER BY total DESC;\\"}},\\"parameter_mappings\\":[],\\"display\\":\\"pie\\",\\"collection_preview\\":true,\\"visualization_settings\\":{\\"pie.dimension\\":\\"estado\\",\\"pie.metric\\":\\"total\\"},\\"parameters\\":[]}","{\\"description\\":\\"Evolución mensual de ingresos totales para identificar tendencias y estacionalidad.\\",\\"archived\\":false,\\"collection_position\\":null,\\"table_id\\":null,\\"database_id\\":2,\\"enable_embedding\\":false,\\"collection_id\\":null,\\"query_type\\":\\"native\\",\\"name\\":\\"Ingresos totales por mes\\",\\"type\\":\\"question\\",\\"embedding_params\\":null,\\"cache_ttl\\":null,\\"dataset_query\\":{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    DATE_TRUNC('month', p.fecha) AS mes,\\\\r\\\\n    SUM(p.monto) AS ingresos_totales\\\\r\\\\nFROM pago p\\\\r\\\\nGROUP BY mes\\\\r\\\\nORDER BY mes;\\"}},\\"parameter_mappings\\":[],\\"display\\":\\"line\\",\\"collection_preview\\":true,\\"visualization_settings\\":{\\"graph.dimensions\\":[\\"mes\\"],\\"graph.metrics\\":[\\"ingresos_totales\\"]},\\"parameters\\":[]}","{\\"description\\":\\"Gasto promedio por pedido según segmento (VIP, regular, nuevo) para personalizar estrategias comerciales.\\",\\"archived\\":false,\\"collection_position\\":null,\\"table_id\\":null,\\"database_id\\":2,\\"enable_embedding\\":false,\\"collection_id\\":null,\\"query_type\\":\\"native\\",\\"name\\":\\"Ticket promedio por segmento de cliente\\",\\"type\\":\\"question\\",\\"embedding_params\\":null,\\"cache_ttl\\":null,\\"dataset_query\\":{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    cl.segmento,\\\\r\\\\n    ROUND(AVG(p.monto), 2) AS ticket_promedio,\\\\r\\\\n    COUNT(DISTINCT pe.id_pedido) AS total_pedidos\\\\r\\\\nFROM pago p\\\\r\\\\nJOIN pedido pe ON p.id_pedido = pe.id_pedido\\\\r\\\\nJOIN cliente cl ON pe.id_cliente = cl.id_cliente\\\\r\\\\nWHERE pe.estado = 'completado'\\\\r\\\\nGROUP BY cl.segmento\\\\r\\\\nORDER BY ticket_promedio DESC;\\"}},\\"parameter_mappings\\":[],\\"display\\":\\