 líneas más y menos rentables.\\",\\"archived\\":false,\\"collection_position\\":null,\\"table_id\\":null,\\"database_id\\":2,\\"enable_embedding\\":false,\\"collection_id\\":null,\\"query_type\\":\\"native\\",\\"name\\":\\"Margen de ganancia por categoría\\",\\"type\\":\\"question\\",\\"embedding_params\\":null,\\"cache_ttl\\":null,\\"dataset_query\\":{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    c.nombre AS categoria,\\\\r\\\\n    ROUND(SUM(dp.cantidad * pr.precio_venta), 2) AS ingresos_venta,\\\\r\\\\n    ROUND(SUM(dp.cantidad * pr.precio_costo), 2) AS costo_total,\\\\r\\\\n    ROUND(SUM(dp.cantidad * (pr.precio_venta - pr.precio_costo)), 2) AS margen_bruto,\\\\r\\\\n    ROUND(\\\\r\\\\n        AVG((pr.precio_venta - pr.precio_costo) / pr.precio_venta * 100), 2\\\\r\\\\n    ) AS margen_porcentaje\\\\r\\\\nFROM detalle_pedido dp\\\\r\\\\nJOIN producto pr ON dp.id_producto = pr.id_producto\\\\r\\\\nJOIN categoria c ON pr.id_categoria = c.id_categoria\\\\r\\\\nJOIN pedido pe ON dp.id_pedido = pe.id_pedido\\\\r\\\\nWHERE pe.estado = 'completado'\\\\r\\\\nGROUP BY c.nombre\\\\r\\\\nORDER BY margen_bruto DESC;\\"}},\\"parameter_mappings\\":[],\\"display\\":\\"bar\\",\\"collection_preview\\":true,\\"visualization_settings\\":{\\"graph.dimensions\\":[\\"categoria\\"],\\"graph.metrics\\":[\\"margen_bruto\\"]},\\"parameters\\":[]}"]	\N	294	f	full	\N	2026-05-19 01:00:22.137184+00
