"base-type\\":\\"type/Float\\"}]]],\\"breakout\\":[[\\"field\\",\\"Age\\",{\\"base-type\\":\\"type/BigInteger\\",\\"binning\\":{\\"strategy\\":\\"num-bins\\",\\"num-bins\\":10}}]],\\"source-table\\":\\"card__2\\"}}","{\\"database\\":1,\\"type\\":\\"query\\",\\"query\\":{\\"expressions\\":{\\"Age\\":[\\"datetime-diff\\",[\\"field\\",49,{\\"base-type\\":\\"type/Date\\",\\"join-alias\\":\\"People - User\\"}],[\\"now\\"],\\"year\\"]},\\"joins\\":[{\\"alias\\":\\"People - User\\",\\"strategy\\":\\"left-join\\",\\"condition\\":[\\"=\\",[\\"field\\",43,{\\"base-type\\":\\"type/Integer\\"}],[\\"field\\",46,{\\"base-type\\":\\"type/BigInteger\\",\\"join-alias\\":\\"People - User\\"}]],\\"source-table\\":3}],\\"source-table\\":5}}","{\\"database\\":1,\\"type\\":\\"query\\",\\"query\\":{\\"filter\\":[\\">\\",[\\"field\\",\\"count\\",{\\"base-type\\":\\"type/Integer\\"}],108],\\"source-query\\":{\\"aggregation\\":[[\\"count\\"]],\\"breakout\\":[[\\"field\\",65,{\\"base-type\\":\\"type/Text\\",\\"source-field\\":40}],[\\"field\\",58,{\\"base-type\\":\\"type/Text\\",\\"source-field\\":40}]],\\"order-by\\":[[\\"desc\\",[\\"aggregation\\",0]]],\\"source-table\\":5,\\"filter\\":[\\"!=\\",[\\"field\\",65,{\\"base-type\\":\\"type/Text\\",\\"source-field\\":40}],\\"Incredible Aluminum Knife\\"]}}}","{\\"database\\":1,\\"type\\":\\"query\\",\\"query\\":{\\"source-table\\":3,\\"expressions\\":{\\"Age\\":[\\"datetime-diff\\",[\\"field\\",49,{\\"base-type\\":\\"type/Date\\"}],[\\"now\\"],\\"year\\"]}}}","{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    cl.segmento,\\\\r\\\\n    ROUND(AVG(p.monto), 2) AS ticket_promedio,\\\\r\\\\n    COUNT(DISTINCT pe.id_pedido) AS total_pedidos\\\\r\\\\nFROM pago p\\\\r\\\\nJOIN pedido pe ON p.id_pedido = pe.id_pedido\\\\r\\\\nJOIN cliente cl ON pe.id_cliente = cl.id_cliente\\\\r\\\\nWHERE pe.estado = 'completado'\\\\r\\\\nGROUP BY cl.segmento\\\\r\\\\nORDER BY ticket_promedio DESC;\\"}}","{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    c.nombre AS categoria,\\\\r\\\\n    ROUND(SUM(dp.cantidad * pr.precio_venta), 2) AS ingresos_venta,\\\\r\\\\n    ROUND(SUM(dp.cantidad * pr.precio_costo), 2) AS costo_total,\\\\r\\\\n    ROUND(SUM(dp.cantidad * (pr.precio_venta - pr.precio_costo)), 2) AS margen_bruto,\\\\r\\\\n    ROUND(\\\\r\\\\n        AVG((pr.precio_venta - pr.precio_costo) / pr.precio_venta * 100), 2\\\\r\\\\n    ) AS margen_porcentaje\\\\r\\\\nFROM detalle_pedido dp\\\\r\\\\nJOIN producto pr ON dp.id_producto = pr.id_producto\\\\r\\\\nJOIN categoria c ON pr.id_categoria = c.id_categoria\\\\r\\\\nJOIN pedido pe ON dp.id_pedido = pe.id_pedido\\\\r\\\\nWHERE pe.estado = 'completado'\\\\r\\\\nGROUP BY c.nombre\\\\r\\\\nORDER BY margen_bruto DESC;\\"}}","{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    DATE_TRUNC('month', p.fecha) AS mes,\\\\r\\\\n    SUM(p.monto) AS ingresos_totales\\\\r\\\\nFROM pago p\\\\r\\\\nGROUP BY mes\\\\r\\\\nORDER BY mes;\\"}}","{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    estado,\\\\r\\\\n    COUNT(*) AS total,\\\\r\\\\n    ROUND(COUNT(*) * 100.0 / SUM(COUNT(*)) OVER (), 2) AS porcentaje\\\\r\\\\nFROM pedido\\\\r\\\\nGROUP BY estado\\\\r\\\\nORDER BY total DESC;\\"}}","{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    pe.canal,\\\\r\\\\n    COUNT(pe.id_pedido) AS total_pedidos,\\\\r\\\\n    SUM(p.monto) AS ingresos_totales\\\\r\\\\nFROM pedido pe\\\\r\\\\nJOIN pago p ON pe.id_pedido = p.id_pedido\\\\r\\\\nWHERE pe.estado = 'completado'\\\\r\\\\nGROUP BY pe.canal;\\"}}","{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    t.nombre AS tienda,\\\\r\\\\n    SUM(p.monto) AS ingresos_totales\\\\r\\\\nFROM pago p\\\\r\\\\nJOIN pedido pe ON p.id_pedido = pe.id_pedido\\\\r\\\\nJOIN tienda t ON pe.id_tienda = t.id_tienda\\\\r\\\\nGROUP BY t.nombre\\\\r\\\\nORDER BY ingresos_totales DESC\\\\r\\\\nLIMIT 5;\\"}}"]	\N	390	f	full	\N	2026-05-16 04:13:06.900073+00
