306	2026-05-19 01:00:14.078708+00	2026-05-19 01:00:14.078708+00	["{\\"constraints\\":{\\"max-results\\":10000,\\"max-results-bare-rows\\":2000},\\"type\\":\\"native\\",\\"middleware\\":{\\"js-int-to-string?\\":true,\\"ignore-cached-results?\\":false,\\"process-viz-settings?\\":false,\\"userland-query?\\":true},\\"cache-strategy\\":null,\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    cl.segmento,\\\\r\\\\n    ROUND(AVG(p.monto), 2) AS ticket_promedio,\\\\r\\\\n    COUNT(DISTINCT pe.id_pedido) AS total_pedidos\\\\r\\\\nFROM pago p\\\\r\\\\nJOIN pedido pe ON p.id_pedido = pe.id_pedido\\\\r\\\\nJOIN cliente cl ON pe.id_cliente = cl.id_cliente\\\\r\\\\nWHERE pe.estado = 'completado'\\\\r\\\\nGROUP BY cl.segmento\\\\r\\\\nORDER BY ticket_promedio DESC;\\"},\\"viz-settings\\":{\\"graph.dimensions\\":[\\"segmento\\"],\\"graph.metrics\\":[\\"ticket_promedio\\"]},\\"database\\":2}","{\\"constraints\\":{\\"max-results\\":10000,\\"max-results-bare-rows\\":2000},\\"type\\":\\"native\\",\\"middleware\\":{\\"js-int-to-string?\\":true,\\"ignore-cached-results?\\":false,\\"process-viz-settings?\\":false,\\"userland-query?\\":true},\\"cache-strategy\\":null,\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    c.nombre AS categoria,\\\\r\\\\n    ROUND(SUM(dp.cantidad * pr.precio_venta), 2) AS ingresos_venta,\\\\r\\\\n    ROUND(SUM(dp.cantidad * pr.precio_costo), 2) AS costo_total,\\\\r\\\\n    ROUND(SUM(dp.cantidad * (pr.precio_venta - pr.precio_costo)), 2) AS margen_bruto,\\\\r\\\\n    ROUND(\\\\r\\\\n        AVG((pr.precio_venta - pr.precio_costo) / pr.precio_venta * 100), 2\\\\r\\\\n    ) AS margen_porcentaje\\\\r\\\\nFROM detalle_pedido dp\\\\r\\\\nJOIN producto pr ON dp.id_producto = pr.id_producto\\\\r\\\\nJOIN categoria c ON pr.id_categoria = c.id_categoria\\\\r\\\\nJOIN pedido pe ON dp.id_pedido = pe.id_pedido\\\\r\\\\nWHERE pe.estado = 'completado'\\\\r\\\\nGROUP BY c.nombre\\\\r\\\\nORDER BY margen_bruto DESC;\\"},\\"viz-settings\\":{\\"graph.dimensions\\":[\\"categoria\\"],\\"graph.metrics\\":[\\"margen_bruto\\"]},\\"database\\":2}","{\\"constraints\\":{\\"max-results\\":10000,\\"max-results-bare-rows\\":2000},\\"type\\":\\"native\\",\\"middleware\\":{\\"js-int-to-string?\\":true,\\"ignore-cached-results?\\":false,\\"process-viz-settings?\\":false,\\"userland-query?\\":true},\\"cache-strategy\\":null,\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    DATE_TRUNC('month', p.fecha) AS mes,\\\\r\\\\n    SUM(p.monto) AS ingresos_totales\\\\r\\\\nFROM pago p\\\\r\\\\nGROUP BY mes\\\\r\\\\nORDER BY mes;\\"},\\"viz-settings\\":{\\"graph.dimensions\\":[\\"mes\\"],\\"graph.metrics\\":[\\"ingresos_totales\\"]},\\"database\\":2}","{\\"constraints\\":{\\"max-results\\":10000,\\"max-results-bare-rows\\":2000},\\"type\\":\\"native\\",\\"middleware\\":{\\"js-int-to-string?\\":true,\\"ignore-cached-results?\\":false,\\"process-viz-settings?\\":false,\\"userland-query?\\":true},\\"cache-strategy\\":null,\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    estado,\\\\r\\\\n    COUNT(*) AS total,\\\\r\\\\n    ROUND(COUNT(*) * 100.0 / SUM(COUNT(*)) OVER (), 2) AS porcentaje\\\\r\\\\nFROM pedido\\\\r\\\\nGROUP BY estado\\\\r\\\\nORDER BY total DESC;\\"},\\"viz-settings\\":{\\"pie.dimension\\":\\"estado\\",\\"pie.metric\\":\\"total\\"},\\"database\\":2}","{\\"constraints\\":{\\"max-results\\":10000,\\"max-results-bare-rows\\":2000},\\"type\\":\\"native\\",\\"middleware\\":{\\"js-int-to-string?\\":true,\\"ignore-cached-results?\\":false,\\"process-viz-settings?\\":false,\\"userland-query?\\":true},\\"cache-strategy\\":null,\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    pe.canal,\\\\r\\\\n    COUNT(pe.id_pedido) AS total_pedidos,\\\\r\\\\n    SUM(p.monto) AS ingresos_totales\\\\r\\\\nFROM pedido pe\\\\r\\\\nJOIN pago p ON pe.id_pedido = p.id_pedido\\\\r\\\\nWHERE pe.estado = 'completado'\\\\r\\\\nGROUP BY pe.canal;\\"},\\"viz-settings\\":{\\"pie.dimension\\":\\"canal\\",\\"pie.metric\\":\\"ingresos_totales\\"},\\"database\\":2}","{\\"constraints\\":{\\"max-results\\":10000,\\"max-results-bare-rows\\":2000},\\"type\\":\\"native\\",\\"middleware\\":{\\"js-int-to-string?\\":true,\\"ignore-cached-results?\\":false,\\"process-viz-settings?\\":false,\\"userland-query?\\":true},\\"cache-strategy\\":null,\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT\\\\r\\\\n    t.nombre AS tienda,\\\\r\\\\n    SUM(p.monto) AS ingresos_totales\\\\r\\\\nFROM pago p\\\\r\\\\nJOIN pedido pe ON p.id_pedido = pe.id_pedido\\\\r\\\\nJOIN tienda t ON pe.id_tienda = t.id_tienda\\\\r\\\\nGROUP BY t.nombre\\\\r\\\\nORDER BY ingresos_totales DESC\\\\r\\\\nLIMIT 5;\\"},\\"viz-settings\\":{\\"graph.dimensions\\":[\\"tienda\\"],\\"graph.metrics\\":[\\"ingresos_totales\\"]},\\"database\\":2}","{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"query\\":\\"SELECT\\\\r\\\\n    cl.segmento,\\\\r\\\\n    ROUND(AVG(p.monto), 2) AS ticket_promedio,\\\\r\\\\n    COUNT(DISTINCT pe.id_pedido) AS total_pedidos\\\\r\\\\nFROM pago p\\\\r\\\\nJOIN pedido pe ON p.id_pedido = pe.id_pedido\\\\r\\\\nJOIN cliente cl ON pe.id_cliente = cl.id_cliente\\\\r\\\\nWHERE pe.estado = 'completado'\\\\r\\\\nGROUP BY cl.segmento\\\\r\\\\nORDER BY ticket_promedio DESC;\\",\\"template-tags\\":{}},\\"middleware\\":{\\"js-int-to-string?\\":true,\\"userland-query?\\":true,\\"add-default-userland-constraints?\\":true}}","{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"query\\":\\"SELECT\\\\r\\\\n    c.nombre AS categoria,\\\\r\\\\n    ROUND(SUM(dp.cantidad * pr.precio_venta), 2) AS ingresos_venta,\\\\r\\\\n    ROUND(SUM(dp.cantidad * pr.precio_costo), 2) AS costo_total,\\\\r\\\\n    ROUND(SUM(dp.cantidad * (pr.precio_venta - pr.precio_costo)), 2) AS margen_bruto,\\\\r\\\\n    ROUND(\\\\r\\\\n        AVG((pr.precio_venta - pr.precio_costo) / pr.precio_venta * 100), 2\\\\r\\\\n    ) AS margen_porcentaje\\\\r\\\\nFROM detalle_pedido dp\\\\r\\\\nJOIN producto pr ON dp.id_producto = pr.id_producto\\\\r\\\\nJOIN categoria c ON pr.id_categoria = c.id_categoria\\\\r\\\\nJOIN pedido pe ON dp.id_pedido = pe.id_pedido\\\\r\\\\nWHERE pe.estado = 'completado'\\\\r\\\\nGROUP BY c.nombre\\\\r\\\\nORDER BY margen_bruto DESC;\\",\\"template-tags\\":{}},\\"middleware\\":{\\"js-int-to-string?\\":true,\\"userland-query?\\":true,\\"add-default-userland-constraints?\\":true}}","{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"query\\":\\"SELECT\\\\r\\\\n    DATE_TRUNC('month', p.fecha) AS mes,\\\\r\\\\n    SUM(p.monto) AS ingresos_totales\\\\r\\\\nFROM pago p\\\\r\\\\nGROUP BY mes\\\\r\\\\nORDER BY mes;\\",\\"template-tags\\":{}},\\"middleware\\":{\\"js-int-to-string?\\":true,\\"userland-query?\\":true,\\"add-default-userland-constraints?\\":true}}","{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"query\\":\\"SELECT\\\\r\\\\n    estado,\\\\r\\\\n    COUNT(*) AS total,\\\\r\\\\n    ROUND(COUNT(*) * 100.0 / SUM(COUNT(*)) OVER (), 2) AS porcentaje\\\\r\\\\nFROM pedido\\\\r\\\\nGROUP BY estado\\\\r\\\\nORDER BY total DESC;\\",\\"template-tags\\":{}},\\"middleware\\":{\\"js-int-to-string?\\":true,\\"userland-query?\\":true,\\"add-default-userland-constraints?\\":true}}","{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"query\\":\\"SELECT\\\\r\\\\n    pe.canal,\\\\r\\\\n    COUNT(pe.id_pedido) AS total_pedidos,\\\\r\\\\n    SUM(p.monto) AS ingresos_totales\\\\r\\\\nFROM pedido pe\\\\r\\\\nJOIN pago p ON pe.id_pedido = p.id_pedido\\\\r\\\\nWHERE pe.estado = 'completado'\\\\r\\\\nGROUP BY pe.canal;\\",\\"template-tags\\":{}},\\"middleware\\":{\\"js-int-to-string?\\":true,\\"userland-query?\\":true,\\"add-default-userland-constraints?\\":true}}","{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"query\\":\\"SELECT\\\\r\\\\n    t.nombre AS tienda,\\\\r\\\\n    SUM(p.monto) AS ingresos_totales\\\\r\\\\nFROM pago p\\\\r\\\\nJOIN pedido pe ON p.id_pedido = pe.id_pedido\\\\r\\\\nJOIN tienda t ON pe.id_tienda = t.id