30	2026-05-16 04:33:45.404199+00	2026-05-16 04:38:46.462705+00	Margen de ganancia por categoría	Rentabilidad bruta por categoría de producto para identificar líneas más y menos rentables.	bar	{"database":2,"type":"native","native":{"template-tags":{},"query":"SELECT\\r\\n    c.nombre AS categoria,\\r\\n    ROUND(SUM(dp.cantidad * pr.precio_venta), 2) AS ingresos_venta,\\r\\n    ROUND(SUM(dp.cantidad * pr.precio_costo), 2) AS costo_total,\\r\\n    ROUND(SUM(dp.cantidad * (pr.precio_venta - pr.precio_costo)), 2) AS margen_bruto,\\r\\n    ROUND(\\r\\n        AVG((pr.precio_venta - pr.precio_costo) / pr.precio_venta * 100), 2\\r\\n    ) AS margen_porcentaje\\r\\nFROM detalle_pedido dp\\r\\nJOIN producto pr ON dp.id_producto = pr.id_producto\\r\\nJOIN categoria c ON pr.id_categoria = c.id_categoria\\r\\nJOIN pedido pe ON dp.id_pedido = pe.id_pedido\\r\\nWHERE pe.estado = 'completado'\\r\\nGROUP BY c.nombre\\r\\nORDER BY margen_bruto DESC;"}}	{"graph.metrics":["margen_bruto"],"graph.dimensions":["categoria"]}	1	2	\N	native	f	\N	\N	\N	f	\N	\N	[{"display_name":"categoria","field_ref":["field","categoria",{"base-type":"type/Text"}],"base_type":"type/Text","effective_type":"type/Text","name":"categoria","semantic_type":null,"fingerprint":{"global":{"distinct-count":15,"nil%":0.0},"type":{"type/Text":{"percent-json":0.0,"percent-url":0.0,"percent-email":0.0,"percent-state":0.0,"average-length":10.733333333333333}}}},{"display_name":"ingresos_venta","field_ref":["field","ingresos_venta",{"base-type":"type/Decimal"}],"base_type":"type/Decimal","effective_type":"type/Decimal","name":"ingresos_venta","semantic_type":null,"fingerprint":{"global":{"distinct-count":15,"nil%":0.0},"type":{"type/Number":{"min":269490.0,"q1":448930.0,"q3":4008505.0,"max":6996300.0,"sd":2169769.0459834486,"avg":2229678.2666666666}}}},{"display_name":"costo_total","field_ref":["field","costo_total",{"base-type":"type/Decimal"}],"base_type":"type/Decimal","effective_type":"type/Decimal","name":"costo_total