34	2026-05-19 00:54:58.987499+00	2026-05-19 00:54:58.987499+00	Crecimiento mensual de clientes nuevos	Indicador 8. Clientes registrados por mes con variación % vs mes anterior y acumulado.	combo	{"type":"native","database":2,"native":{"query":"WITH mes AS (\\n    SELECT\\n        DATE_TRUNC('month', fecha_registro)::date AS mes,\\n        COUNT(*)                                  AS nuevos_clientes\\n    FROM cliente\\n    GROUP BY 1\\n)\\nSELECT\\n    mes,\\n    nuevos_clientes,\\n    nuevos_clientes - LAG(nuevos_clientes) OVER (ORDER BY mes)        AS delta_abs,\\n    ROUND(\\n        100.0 * (nuevos_clientes - LAG(nuevos_clientes) OVER (ORDER BY mes))\\n              / NULLIF(LAG(nuevos_clientes) OVER (ORDER BY mes), 0),\\n        2\\n    )                                                                  AS variacion_pct,\\n    SUM(nuevos_clientes) OVER (ORDER BY mes)                           AS acumulado\\nFROM mes\\nORDER BY mes;"}}	{"graph.dimensions":["mes"],"graph.metrics":["nuevos_clientes","variacion_pct"],"series_settings":{"nuevos_clientes":{"display":"bar","axis":"left"},"variacion_pct":{"display":"line","axis":"right"}},"graph.x_axis.title_text":"Mes","graph.y_axis.title_text":"Clientes nuevos"}	1	2	\N	native	f	\N	\N	\N	f	\N	\N	[{"display_name":"mes","field_ref":["field","mes",{"base-type":"type/Date"}],"base_type":"type/Date","effective_type":"type/Date","name":"mes","semantic_type":null,"fingerprint":{"global":{"distinct-count":1,"nil%":0.0},"type":{"type/DateTime":{"earliest":"2022-01-01T00:00:00-06:00","latest":"2022-01-01T00:00:00-06:00"}}}},{"display_name":"nuevos_clientes","field_ref":["field","nuevos_clientes",{"base-type":"type/BigInteger"}],"base_type":"type/BigInteger","effective_type":"type/BigInteger","name":"nuevos_clientes","semantic_type":null,"fingerprint":{"global":{"distinct-count":1,"nil%":0.0},"type":{"type/Number":{"min":19.0,"q1":19.0,"q3":19.0,"max":19.0,"sd":null,"avg":19.0}}}},{"display_name":"delta_abs","field_ref":["field",