35	2026-05-19 00:55:03.40603+00	2026-05-19 00:55:03.513787+00	Tiendas: rendimiento vs promedio	Indicador 9. Ingresos por tienda contra el promedio global. Identifica tiendas BAJO/SOBRE el benchmark.	bar	{"type":"native","database":2,"native":{"query":"WITH ingresos_tienda AS (\\n    SELECT\\n        t.id_tienda,\\n        t.nombre  AS tienda,\\n        t.region,\\n        SUM(dp.cantidad * dp.precio_unitario * (1 - dp.descuento/100.0)) AS ingresos\\n    FROM pedido p\\n    JOIN detalle_pedido dp ON dp.id_pedido = p.id_pedido\\n    JOIN tienda         t  ON t.id_tienda  = p.id_tienda\\n    WHERE p.estado = 'completado'\\n    GROUP BY t.id_tienda, t.nombre, t.region\\n),\\nprom AS (SELECT AVG(ingresos) AS promedio_global FROM ingresos_tienda)\\nSELECT\\n    i.tienda,\\n    i.region,\\n    ROUND(i.ingresos, 2)                                                AS ingresos,\\n    ROUND(prom.promedio_global, 2)                                      AS promedio_global,\\n    ROUND(i.ingresos - prom.promedio_global, 2)                         AS gap_absoluto,\\n    ROUND(100.0 * (i.ingresos - prom.promedio_global) / prom.promedio_global, 2) AS gap_pct,\\n    CASE WHEN i.ingresos < prom.promedio_global THEN 'BAJO' ELSE 'SOBRE' END     AS bajo_rendimiento\\nFROM ingresos_tienda i\\nCROSS JOIN prom\\nORDER BY i.ingresos ASC;"}}	{"graph.dimensions":["tienda"],"graph.metrics":["ingresos"],"graph.show_goal":true,"graph.goal_value":3963845.91,"graph.goal_label":"Promedio global","graph.show_values":true}	1	2	\N	native	f	\N	\N	\N	f	\N	\N	[{"display_name":"tienda","field_ref":["field","tienda",{"base-type":"type/Text"}],"base_type":"type/Text","effective_type":"type/Text","name":"tienda","semantic_type":null,"fingerprint":{"global":{"distinct-count":1,"nil%":0.0},"type":{"type/Text":{"percent-json":0.0,"percent-url":0.0,"percent-email":0.0,"percent-state":0.0,"average-length":16.0}}}},{"display_name":"region","field_ref":["field","region",{"base-type":"type/Text"}],"base_type":"type/Tex