9	Card	30	1	2026-05-16 04:33:45.432619+00	{"description":"Rentabilidad bruta por categoría de producto para identificar líneas más y menos rentables.","archived":false,"collection_position":null,"table_id":null,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"Margen de ganancia por categoría","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"database":2,"type":"native","native":{"template-tags":{},"query":"SELECT\\r\\n    c.nombre AS categoria,\\r\\n    ROUND(SUM(dp.cantidad * pr.precio_venta), 2) AS ingresos_venta,\\r\\n    ROUND(SUM(dp.cantidad * pr.precio_costo), 2) AS costo_total,\\r\\n    ROUND(SUM(dp.cantidad * (pr.precio_venta - pr.precio_costo)), 2) AS margen_bruto,\\r\\n    ROUND(\\r\\n        AVG((pr.precio_venta - pr.precio_costo) / pr.precio_venta * 100), 2\\r\\n    ) AS margen_porcentaje\\r\\nFROM detalle_pedido dp\\r\\nJOIN producto pr ON dp.id_producto = pr.id_producto\\r\\nJOIN categoria c ON pr.id_categoria = c.id_categoria\\r\\nJOIN pedido pe ON dp.id_pedido = pe.id_pedido\\r\\nWHERE pe.estado = 'completado'\\r\\nGROUP BY c.nombre\\r\\nORDER BY margen_bruto DESC;"}},"parameter_mappings":[],"display":"bar","collection_preview":true,"visualization_settings":{"graph.dimensions":["categoria"],"graph.metrics":["margen_bruto"]},"parameters":[]}	f	t	\N	t	v0.50.20 (df82d58)
11	Card	31	1	2026-05-16 04:35:04.377128+00	{"description":"Distribución de pedidos por estado (completado, cancelado, devuelto, pendiente) para identificar el nivel de riesgo operacional del negocio.","archived":false,"collection_position":null,"table_id":null,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"Tasa de pedidos cancelados y devueltos","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"database":2,"type":"native","native":{"template-tags":{},"query":"SELECT\\r\\n    estado,\\r\\n    COUNT(*) AS total,\\r\\n    ROUND(COUNT(*) * 100.0 / SUM(COUNT(*)) OVER (), 2) AS porcentaje\\r\\nFROM pedido\\r\\nGROUP BY estado\\r\\nORDER BY total DESC;"}},"parameter_mappings":[],"display":"pie","collection_preview":true,"visualization_settings":{"pie.dimension":"estado","pie.metric":"total"},"parameters":[]}	f	t	\N	t	v0.50.20 (df82d58)
10	Dashboard	2	1	2026-05-16 04:34:13.537646+00	{"description":null,"archived":false,"collection_position":null,"tabs":[],"enable_embedding":false,"collection_id":null,"name":"Estrategia y Expansión Comercial","width":"fixed","embedding_params":null,"cache_ttl":null,"cards":[{"size_x":12,"dashboard_tab_id":null,"series":[],"action_id":null,"col":0,"id":32,"parameter_mappings":[],"card_id":27,"visualization_settings":{},"size_y":6,"dashboard_id":2,"row":0},{"size_x":12,"dashboard_tab_id":null,"series":[],"action_id":null,"col":12,"id":33,"parameter_mappings":[],"card_id":28,"visualization_settings":{},"size_y":6,"dashboard_id":2,"row":0},{"size_x":12,"dashboard_tab_id":null,"series":[],"action_id":null,"col":0,"id":34,"parameter_mappings":[],"card_id":29,"visualization_settings":{},"size_y":7,"dashboard_id":2,"row":6},{"size_x":24,"dashboard_tab_id":null,"series":[],"action_id":null,"col":0,"id":35,"parameter_mappings":[],"card_id":30,"visualization_settings":{},"size_y":7,"dashboard_id":2,"row":13}],"parameters":[],"auto_apply_filters":true}	f	f	\N	f	v0.50.20 (df82d58)
13	Card	32	1	2026-05-16 04:37:02.164525+00	{"description":"Gasto promedio por pedido según segmento (VIP, regular, nuevo) para personalizar estrategias comerciales.","archived":false,"collection_position":null,"table_id":null,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"Ticket promedio por segmento de cliente","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"database":2,"type":"native","native":{"template-tags":{},"query":"SELECT\\r\\n    cl.segmento,\\r\\n    ROUND(AVG(p.monto), 2) AS ticket_promedio,\\r\\n    COUNT(DISTINCT pe.id_pedido) AS total_pedidos\\r\\nFROM pago p\\r\\nJOIN pedido pe ON p.id_pedido = pe.id_pedido\\r\\nJOIN cliente cl ON pe.id_cliente = cl.id_cliente\\r\\nWHERE pe.estado = 'completado'\\r\\nGROUP BY cl.segmento\\r\\nORDER BY ticket_promedio DESC;"}},"parameter_mappings":[],"display":"bar","collection_preview":true,"visualization_settings":{"graph.dimensions":["segmento"],"graph.metrics":["ticket_promedio"]},"parameters":[]}	f	t	\N	t	v0.50.20 (df82d58)
12	Dashboard	2	1	2026-05-16 04:36:03.383696+00	{"description":null,"archived":false,"collection_position":null,"tabs":[],"enable_embedding":false,"collection_id":null,"name":"Estrategia y Expansión Comercial","width":"fixed","embedding_params":null,"cache_ttl":null,"cards":[{"size_x":12,"dashboard_tab_id":null,"series":[],"action_id":null,"col":0,"id":32,"parameter_mappings":[],"card_id":27,"visualization_settings":{},"size_y":6,"dashboard_id":2,"row":0},{"size_x":12,"dashboard_tab_id":null,"series":[],"action_id":null,"col":12,"id":33,"parameter_mappings":[],"card_id":28,"visualization_settings":{},"size_y":6,"dashboard_id":2,"row":0},{"size_x":12,"dashboard_tab_id":null,"series":[],"action_id":null,"col":0,"id":34,"parameter_mappings":[],"card_id":29,"visualization_settings":{},"size_y":7,"dashboard_id":2,"row":6},{"size_x":12,"dashboard_tab_id":null,"series":[],"action_id":null,"col":0,"id":35,"parameter_mappings":[],"card_id":30,"visualization_settings":{},"size_y":7,"dashboard_id":2,"row":13},{"size_x":12,"dashboard_tab_id":null,"series":[],"action_id":null,"col":12,"id":36,"parameter_mappings":[],"card_id":31,"visualization_settings":{},"size_y":7,"dashboard_id":2,"row":6}],"parameters":[],"auto_apply_filters":true}	f	f	\N	f	v0.50.20 (df82d58)
15	Card	33	1	2026-05-19 00:54:56.360075+00	{"description":"Indicador 7. Ingresos netos (post-descuento) agrupados por región. Solo pedidos completados.","archived":false,"collection_position":null,"table_id":null,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"Ingresos por región","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"type":"native","database":2,"native":{"query":"SELECT\\n    t.region                                                                AS region,\\n    ROUND(SUM(dp.cantidad * dp.precio_unitario * (1 - dp.descuento/100.0)), 2) AS ingresos,\\n    COUNT(DISTINCT p.id_pedido)                                             AS pedidos,\\n    COUNT(DISTINCT t.id_tienda)                                             AS tiendas\\nFROM pedido p\\nJOIN detalle_pedido dp ON dp.id_pedido = p.id_pedido\\nJOIN tienda         t  ON t.id_tienda  = p.id_tienda\\nWHERE p.estado = 'completado'\\nGROUP BY t.region\\nORDER BY ingresos DESC;"}},"parameter_mappings":[],"display":"bar","collection_preview":true,"visualization_settings":{"graph.dimensions":["region"],"graph.show_values":true,"graph.y_axis.title_text":"Ingresos (Q)","stackable.stack_type":null,"graph.metrics":["ingresos"]},"parameters":[]}	f	t	\N	t	v0.50.20 (df82d58)
16	Card	34	1	2026-05-19 00:54:59.090244+00	{"description":"Indicador 8. Clientes registrados por mes con variación % vs mes anterior y acumulado.","archived":false,"collection_position":null,"table_id":null,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"Crecimiento mensual de clientes nuevos","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"type":"native","database":2,"native":{"query":"WITH mes AS (\\n    SELECT\\n        DATE_TRUNC('month', fecha_registro)::date AS mes,\\n        COUNT(*)                                  AS nuevos_clientes\\n    FROM cliente\\n    GROUP BY 1\\n)\\nSELECT\\n    mes,\\n    nuevos_clientes,\\n    nuevos_clientes - LAG(nuevos_clientes) OVER (ORDER BY mes)        AS delta_abs,\\n    ROUND(\\n        100.0 * (nuevos_clientes - LAG(nuevos_clientes) OVER (ORDER BY mes))\\n              / NULLIF(LAG(nuevos_clientes) OVER (ORDER BY mes), 0),\\n        2\\n    )                                                                  AS variacion_pct,\\n    SUM(nuevos_clientes) OVER (ORDER BY mes)                           AS acumulado\\nFROM mes\\nORDER BY mes;"}},"parameter_mappings":[],"display":"combo","collection_preview":true,"visualization_settings":{"graph.dimensions":["mes"],"series_settings":{"nuevos_clientes":{"display":"bar","axis":"left"},"variacion_pct":{"display":"line","axis":"right"}},"graph.x_axis.title_text":"Mes","graph.y_axis.title_text":"Clientes nuevos","graph.metrics":["nuevos_clientes","variacion_pct"]},"parameters":[]}	f	t	\N	t	v0.50.20 (df82d58)
17	Card	35	1	2026-05-19 00:55:03.438926+00	{"description":"Indicador 9. Ingresos por tienda contra el promedio global. Identifica tiendas BAJO/SOBRE el benchmark.","archived":false,"collection_position":null,"table_id":null,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"Tiendas: rendimiento vs promedio","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"type":"native","database":2,"native":{"query":"WITH ingresos_tienda AS (\\n    SELECT\\n        t.id_tienda,\\n        t.nombre  AS tienda,\\n        t.region,\\n        SUM(dp.cantidad * dp.precio_unitario * (1 - dp.descuento/100.0)) AS ingresos\\n    FROM pedido p\\n    JOIN detalle_pedido dp ON dp.id_pedido = p.id_pedido\\n    JOIN tienda         t  ON t.id_tienda  = p.id_tienda\\n    WHERE p.estado = 'completado'\\n    GROUP BY t.id_tienda, t.nombre, t.region\\n),\\nprom AS (SELECT AVG(ingresos) AS promedio_global FROM ingresos_tienda)\\nSELECT\\n    i.tienda,\\n    i.region,\\n    ROUND(i.ingresos, 2)                                                AS ingresos,\\n    ROUND(prom.promedio_global, 2)                                      AS promedio_global,\\n    ROUND(i.ingresos - prom.promedio_global, 2)                         AS gap_absoluto,\\n    ROUND(100.0 * (i.ingresos - prom.promedio_global) / prom.promedio_global, 2) AS gap_pct,\\n    CASE WHEN i.ingresos < prom.promedio_global THEN 'BAJO' ELSE 'SOBRE' END     AS bajo_rendimiento\\nFROM ingresos_tienda i\\nCROSS JOIN prom\\nORDER BY i.ingresos ASC;"}},"parameter_mappings":[],"display":"bar","collection_preview":true,"visualization_settings":{"graph.dimensions":["tienda"],"graph.show_goal":true,"graph.goal_value":3963845.91,"graph.goal_label":"Promedio global","graph.show_values":true,"graph.metrics":["ingresos"]},"parameters":[]}	f	t	\N	t	v0.50.20 (df82d58)
18	Card	36	1	2026-05-19 00:55:03.645728+00	{"description":"Indicador 10. Ingresos mensuales comparados entre 2024, 2025 y 2026. Misma X (mes) para detectar estacionalidad y crecimiento.","archived":false,"collection_position":null,"table_id":null,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"Evolución de ventas YoY (2024 vs 2025 vs 2026)","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"type":"native","database":2,"native":{"query":"SELECT\\n    EXTRACT(YEAR  FROM p.fecha)::int                                        AS anio,\\n    EXTRACT(MONTH FROM p.fecha)::int                                        AS mes_num,\\n    TO_CHAR(p.fecha, 'Mon')                                                 AS mes_label,\\n    ROUND(SUM(dp.cantidad * dp.precio_unitario * (1 - dp.descuento/100.0)), 2) AS ingresos,\\n    COUNT(DISTINCT p.id_pedido)                                             AS pedidos\\nFROM pedido p\\nJOIN detalle_pedido dp ON dp.id_pedido = p.id_pedido\\nWHERE p.estado = 'completado'\\nGROUP BY 1, 2, 3\\nORDER BY anio, mes_num;"}},"parameter_mappings":[],"display":"line","collection_preview":true,"visualization_settings":{"graph.dimensions":["mes_num","anio"],"graph.x_axis.title_text":"Mes","graph.y_axis.title_text":"Ingresos (Q)","graph.metrics":["ingresos"]},"parameters":[]}	f	t	\N	t	v0.50.20 (df82d58)
